#!/bin/sh
# Commands equivalent to this certification run.
# Generated by `cavs certify` — reproduce by running them in order.
set -e

cavs signature export --raw steampipe-cases/datasets/godot-pck-localized/old/game.pck -o artifacts/old.cavssig
cavs signature export --raw steampipe-cases/datasets/godot-pck-localized/new/game.pck -o artifacts/new.cavssig
cavs diff-plan steampipe-cases/datasets/godot-pck-localized/old/game.pck steampipe-cases/datasets/godot-pck-localized/new/game.pck --out artifacts/update.cavsplan
cavs apply --old steampipe-cases/datasets/godot-pck-localized/old/game.pck --plan artifacts/update.cavsplan --out <tmp> --verify
cavs bench routes --old steampipe-cases/datasets/godot-pck-localized/old/game.pck --new steampipe-cases/datasets/godot-pck-localized/new/game.pck --out artifacts/route-bench
cavs analyze godot-pck steampipe-cases/datasets/godot-pck-localized/old/game.pck steampipe-cases/datasets/godot-pck-localized/new/game.pck --out godot-pck-analysis.md
